class Solution:
    def largestTimeFromDigits(self, arr) -> str:
        from itertools import permutations
        best = ''
        for p in permutations(arr):
            h = p[0] * 10 + p[1]
            m = p[2] * 10 + p[3]
            if 0 <= h <= 23 and 0 <= m <= 59:
                t = f'{h:02d}:{m:02d}'
                if t > best:
                    best = t
        return best

